def __init__(    self,    url: str,) -> None:    self.url = url    self.browser: Optional[Browser] = None    self.context: Optional[BrowserContext] = None    self._playwright = None    #    # Чтобы одна и та же вкладка    # не подключалась дважды    #    self._attached_pages: set[int] = set()    #    # Capture Engine    #    self.capture = CaptureManager()    #    # Register plugins    #    self.capture.register(        RequestCapture()    )    self.capture.register(        ResponseCapture()    )    self.capture.register(        GraphQLCapture()    )    self.capture.register(        HtmlCapture()    )    self.capture.register(        ScreenshotCapture()    )    self.capture.register(        CookieCapture()    )